import React, { useMemo, useState } from 'react';
import { Pressable, Text, View } from 'react-native';
import Animated, { useAnimatedStyle, useSharedValue, withSpring } from 'react-native-reanimated';
import { Gesture, GestureDetector } from 'react-native-gesture-handler';

export function BundleSizeTreeShakingHeavyImports() {
  const [enabled, setEnabled] = useState(false);
  const offset = useSharedValue(0);
  const gesture = useMemo(() => Gesture.Pan()
    .onChange((event) => { offset.value = event.translationX; })
    .onEnd(() => { offset.value = withSpring(0); }), []);
  const style = useAnimatedStyle(() => ({ transform: [{ translateX: offset.value }] }));

  return (
    <GestureDetector gesture={gesture}>
      <Animated.View style={style} accessible accessibilityRole="button" accessibilityState={{ selected: enabled }} accessibilityLabel="Bundle size: tree-shaking heavy imports">
        <Pressable onPress={() => setEnabled((v) => !v)}>
          <Text>Bundle size: tree-shaking heavy imports</Text>
        </Pressable>
      </Animated.View>
    </GestureDetector>
  );
}

